{
  "domain_analysis": {
    "business_context": "Refactoring a logistics platform from shipment-level tracking to parcel-level tracking to enable partial delivery detection. Currently the system treats a shipment as an atomic unit with one tracking number and one status. The business needs granular visibility into each parcel's lifecycle within a shipment, enabling scenarios like partial delivery, individual parcel loss, and customer disputes on partial receipt.",
    "bounded_context": "Shipment Tracking & Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "An aggregate root representing the entire customer order fulfillment unit. Contains one or more Parcels. Its status is DERIVED from the collective state of its Parcels — it never has an independently assigned status." },
      { "term": "Parcel", "definition": "An individually trackable physical unit within a Shipment. Each Parcel has its own tracking number, lifecycle, and status. This is the fundamental unit of tracking." },
      { "term": "Parcel Tracking Number", "definition": "A unique identifier assigned to each Parcel enabling independent tracking through the logistics network. Distinct from the Shipment reference number." },
      { "term": "Shipment Reference", "definition": "A business-facing identifier for the overall Shipment. Used for customer communication. NOT a tracking number — parcels have their own tracking numbers." },
      { "term": "Partial Delivery", "definition": "A Shipment state where at least one but not all Parcels have been delivered. Triggers specific business workflows including customer notification and hold periods." },
      { "term": "Proof of Delivery (POD)", "definition": "Evidence that a specific Parcel was delivered — signature, photo, GPS coordinates, timestamp. Captured per-Parcel, not per-Shipment." },
      { "term": "Delivery Attempt", "definition": "A recorded attempt to deliver a specific Parcel, including timestamp, outcome, and reason for failure if applicable." },
      { "term": "Parcel Exception", "definition": "Any deviation from the normal parcel flow — damage, loss, held at customs, address issue. Each exception is scoped to a single Parcel." },
      { "term": "Dispute", "definition": "A customer-initiated claim that the actual receipt of parcels does not match what the system recorded. Scoped to specific Parcels within a Shipment." },
      { "term": "Shipment Completion", "definition": "The state when ALL Parcels in a Shipment have reached a terminal state (Delivered, Lost, or Returned). Only then can the Shipment be considered closed." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Every Parcel MUST have its own unique tracking number, independent of the Shipment reference.",
      "invariant": true,
      "invariant_justification": "Without a unique tracking number per parcel, the system cannot track parcels individually. This is the foundational data integrity requirement for the entire refactor.",
      "testable_assertion": "Given a Shipment with N parcels, there must be exactly N distinct tracking numbers, each assigned to exactly one Parcel."
    },
    {
      "id": "BR-2",
      "rule": "Shipment status MUST be derived from the aggregate state of its Parcels — never set independently.",
      "invariant": true,
      "invariant_justification": "An independently-set Shipment status can contradict parcel reality (e.g., Shipment marked 'Delivered' while parcels are still in transit). This creates corrupt state that breaks downstream processes like billing and customer notifications.",
      "testable_assertion": "There is no code path that sets Shipment status directly. Shipment status is always computed from Parcel states."
    },
    {
      "id": "BR-3",
      "rule": "Shipment derived status rules: ALL parcels Created → Shipment 'Created'; ANY parcel In Transit and NONE delivered → 'In Transit'; SOME parcels Delivered but not all terminal → 'Partially Delivered'; ALL parcels Delivered → 'Delivered'; ALL parcels in a terminal state (Delivered/Lost/Returned) but not all Delivered → 'Closed with Exceptions'; ANY parcel Lost and Shipment not yet closed → 'Partially Delivered' or 'In Transit' depending on other parcels.",
      "invariant": true,
      "invariant_justification": "The derivation rules define the mapping from parcel states to shipment state. If the derivation is wrong, partial delivery detection — the core business need — fails.",
      "testable_assertion": "For each combination of parcel states, the derived shipment status matches the defined mapping. Specifically: a shipment with 3/5 parcels Delivered, 2 In Transit → 'Partially Delivered'."
    },
    {
      "id": "BR-4",
      "rule": "Parcel state transitions must follow a defined state machine: Created → Picked Up → In Transit → Out for Delivery → Delivered. Exceptions branch: any non-terminal state → Lost, Damaged, or Held. Recovery paths: Held → back to In Transit; Damaged → Returned. Terminal states: Delivered, Lost, Returned.",
      "invariant": true,
      "invariant_justification": "Invalid state transitions (e.g., jumping from Created to Delivered) indicate data corruption or tracking system failure. The physical reality of logistics constrains the order of events.",
      "testable_assertion": "The system rejects any Parcel state transition not in the allowed transition set. E.g., transitioning from 'Created' directly to 'Delivered' is rejected."
    },
    {
      "id": "BR-5",
      "rule": "A Parcel in a terminal state (Delivered, Lost, Returned) cannot transition to any other state.",
      "invariant": true,
      "invariant_justification": "Terminal states represent physical finality. A delivered parcel cannot become un-delivered. Reversals must be modeled as new domain events (e.g., a Dispute or Return Request), not state rollbacks.",
      "testable_assertion": "Any attempt to change the state of a Parcel with status Delivered, Lost, or Returned is rejected by the domain model."
    },
    {
      "id": "BR-6",
      "rule": "Each Parcel delivery MUST capture Proof of Delivery (POD) independently — timestamp, GPS coordinates, and recipient signature or photo.",
      "invariant": true,
      "invariant_justification": "POD is per-parcel because parcels can be delivered at different times, to different people, at different locations. Without per-parcel POD, disputes on partial delivery cannot be resolved.",
      "testable_assertion": "A Parcel cannot transition to 'Delivered' status without an associated POD record containing at minimum a timestamp and one form of evidence."
    },
    {
      "id": "BR-7",
      "rule": "When a Shipment enters 'Partially Delivered' status, the customer MUST be notified with the list of delivered and outstanding parcels.",
      "invariant": false,
      "invariant_justification": "Notification is a business policy, not a data integrity constraint. The timing, channel, and content of notifications can be changed by operations without corrupting system state.",
      "testable_assertion": "When the Nth parcel transitions to Delivered (where N < total parcels), a PartialDeliveryNotification event is emitted containing the shipment reference, delivered parcel IDs, and outstanding parcel IDs."
    },
    {
      "id": "BR-8",
      "rule": "A customer dispute on partial receipt MUST reference specific Parcel(s), not the Shipment as a whole.",
      "invariant": true,
      "invariant_justification": "Disputes trigger investigation and potential financial remediation. Without parcel-level specificity, it is impossible to determine which parcels are contested, investigate their tracking history, or resolve the dispute accurately.",
      "testable_assertion": "The Dispute entity requires at least one Parcel ID. A dispute creation request without parcel references is rejected."
    },
    {
      "id": "BR-9",
      "rule": "A Parcel marked as Lost triggers an investigation workflow and must not be silently absorbed into the Shipment status.",
      "invariant": false,
      "invariant_justification": "The specific investigation workflow (SLA, escalation path, auto-refund threshold) is policy-driven and may vary by carrier, customer tier, or parcel value.",
      "testable_assertion": "When a Parcel transitions to 'Lost', a ParcelLostEvent is emitted. The Shipment status reflects the loss (not 'Delivered'). An investigation record is created linked to the Parcel."
    },
    {
      "id": "BR-10",
      "rule": "Parcels within a Shipment may be fulfilled by different carriers or routes. Each Parcel tracks its own carrier assignment.",
      "invariant": false,
      "invariant_justification": "Multi-carrier fulfillment is a business capability, not a consistency constraint. Some deployments may use single-carrier only.",
      "testable_assertion": "The Parcel entity has a carrier field that is independent of other Parcels in the same Shipment."
    },
    {
      "id": "BR-11",
      "rule": "A Shipment cannot be marked as complete (closed/archived) until ALL of its Parcels are in a terminal state.",
      "invariant": true,
      "invariant_justification": "Closing a shipment while parcels are still in transit would orphan those parcels from the customer-facing tracking flow and break SLA monitoring.",
      "testable_assertion": "Any attempt to close or archive a Shipment that has parcels in non-terminal states is rejected."
    },
    {
      "id": "BR-12",
      "rule": "A Shipment MUST contain at least one Parcel. Empty shipments are invalid.",
      "invariant": true,
      "invariant_justification": "A shipment with zero parcels has no physical meaning and would corrupt status derivation logic (division by zero in completion percentage, undefined aggregate state).",
      "testable_assertion": "Creating a Shipment with zero Parcels is rejected. Removing the last Parcel from a Shipment is rejected."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A Shipment with 5 Parcels, all in 'Created' state",
      "when": "3 Parcels transition to 'Delivered' and 2 remain 'In Transit'",
      "then": "The Shipment status is derived as 'Partially Delivered' and a PartialDeliveryNotification event is emitted listing the 3 delivered and 2 outstanding parcels"
    },
    {
      "id": "AC-2",
      "given": "A Shipment with 5 Parcels where 4 are 'Delivered'",
      "when": "The 5th Parcel transitions to 'Delivered' with valid POD",
      "then": "The Shipment status is derived as 'Delivered' and a ShipmentCompleted event is emitted"
    },
    {
      "id": "AC-3",
      "given": "A Shipment with 5 Parcels where 3 are 'Delivered' and 1 is 'In Transit'",
      "when": "1 Parcel is marked as 'Lost'",
      "then": "The Shipment status remains 'Partially Delivered', a ParcelLostEvent is emitted, and an investigation workflow is initiated for the lost Parcel"
    },
    {
      "id": "AC-4",
      "given": "A Shipment with 5 Parcels where 4 are 'Delivered' and 1 is 'Lost'",
      "when": "All parcels are now in terminal states",
      "then": "The Shipment status is derived as 'Closed with Exceptions' — NOT 'Delivered'"
    },
    {
      "id": "AC-5",
      "given": "A customer views a Shipment with 3 of 5 Parcels delivered",
      "when": "The customer initiates a dispute claiming they received only 2 Parcels",
      "then": "The dispute is created referencing the specific Parcel ID the customer claims was not received, and the dispute record is linked to that Parcel's tracking history and POD"
    },
    {
      "id": "AC-6",
      "given": "A Parcel in 'Delivered' state with POD recorded",
      "when": "An attempt is made to change its status to 'In Transit'",
      "then": "The transition is rejected with an error indicating terminal states are immutable"
    },
    {
      "id": "AC-7",
      "given": "A Parcel in 'Out for Delivery' state",
      "when": "A delivery attempt fails",
      "then": "A DeliveryAttempt record is created with failure reason, the Parcel remains in 'Out for Delivery' or transitions to 'Held' depending on attempt count policy, and the Shipment status is recalculated"
    },
    {
      "id": "AC-8",
      "given": "A Shipment with parcels in non-terminal states",
      "when": "An attempt is made to close or archive the Shipment",
      "then": "The operation is rejected, listing the parcels that are still in non-terminal states"
    },
    {
      "id": "AC-9",
      "given": "A new Shipment is being created",
      "when": "Each Parcel is added to the Shipment",
      "then": "Each Parcel is assigned a unique tracking number distinct from other Parcels in the Shipment and distinct from the Shipment reference"
    },
    {
      "id": "AC-10",
      "given": "A Parcel transitions to 'Delivered'",
      "when": "No Proof of Delivery data is provided",
      "then": "The transition is rejected with an error requiring POD before delivery confirmation"
    }
  ],

  "edge_cases": [
    {
      "scenario": "All parcels in a shipment are lost",
      "expected_behavior": "Shipment status becomes 'Closed with Exceptions' (not 'Lost' — the shipment itself is not a trackable unit). Each parcel has an individual investigation. Customer is entitled to full remediation."
    },
    {
      "scenario": "Customer disputes a parcel marked as Delivered with valid POD (signature + photo)",
      "expected_behavior": "Dispute is created referencing the specific parcel. The POD evidence is preserved and attached to the dispute for investigation. The parcel remains in 'Delivered' state — the dispute is a separate workflow, not a state rollback."
    },
    {
      "scenario": "A parcel is damaged in transit and the customer refuses the remaining delivery",
      "expected_behavior": "Damaged parcel transitions to 'Damaged' → 'Returned'. Refused parcels transition to 'Returned' with reason 'Customer Refused'. Shipment becomes 'Closed with Exceptions' once all parcels reach terminal state."
    },
    {
      "scenario": "Carrier reports delivery of a parcel but the tracking event arrives out of order (delivery event before in-transit event)",
      "expected_behavior": "The system must either enforce state machine ordering by rejecting the out-of-order event, or use event timestamps to reconstruct the correct sequence. The state machine invariant must not be bypassed — if the intermediate states are inferred, they must be explicitly recorded."
    },
    {
      "scenario": "One parcel in a multi-parcel shipment is held at customs indefinitely",
      "expected_behavior": "The parcel enters 'Held' state with reason 'Customs'. Other parcels continue their lifecycle normally. Shipment cannot close until the held parcel resolves. SLA monitoring applies per-parcel."
    },
    {
      "scenario": "Customer requests cancellation after some parcels are already delivered",
      "expected_behavior": "Delivered parcels cannot be un-delivered (terminal state). Cancellation can only apply to parcels not yet in terminal state. The shipment enters a mixed state requiring a return process for delivered parcels and cancellation for in-flight parcels."
    },
    {
      "scenario": "A parcel is split into two parcels mid-transit (repackaging at hub)",
      "expected_behavior": "This is a logistics edge case that requires creating new Parcel entities under the same Shipment. The original parcel transitions to a 'Repackaged' terminal state and the new child parcels inherit the shipment association. The shipment's parcel count changes."
    },
    {
      "scenario": "Two parcels from different shipments are accidentally swapped by the carrier",
      "expected_behavior": "Each parcel retains its tracking number. The mis-delivery is detected when POD location/recipient doesn't match the expected destination. Parcels must not be reassigned between shipments — they are corrected via exception workflows (return + redeliver)."
    }
  ],

  "business_impact": {
    "financial": "Parcel-level tracking enables accurate partial refunds and claims processing. Without it, a single lost parcel in a 5-parcel shipment forces either a full shipment refund (overpaying) or no refund (customer dissatisfaction and chargeback risk). Per-parcel POD reduces fraudulent dispute success rates by providing granular evidence.",
    "operational": "Significant refactor of the core domain model. All existing integrations that consume shipment status must be updated to handle the new derived status model and parcel-level events. Carrier integration layers must map per-parcel tracking events. Warehouse operations must generate per-parcel tracking numbers at pack time. This is a foundational change with broad operational surface area.",
    "user": "Customers gain granular visibility into each parcel's location and status. Partial delivery notifications set correct expectations. Dispute resolution becomes faster and more precise because evidence is parcel-scoped. Customer trust increases when they can see exactly which items are where.",
    "risk": "Migration risk is high — existing shipments with single tracking numbers must be handled (backward compatibility or data migration). API consumers expecting single-status shipments will break without versioning. The derived status logic is a new source of bugs if not thoroughly tested for all parcel state combinations.",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Improved tracking visibility, faster dispute resolution, accurate partial delivery notifications" },
      { "group": "Customer Support", "impact": "Can investigate at parcel level, resolve disputes with per-parcel POD, but must be retrained on new status model" },
      { "group": "Warehouse Operations", "impact": "Must generate and affix individual tracking labels per parcel at pack time — process change required" },
      { "group": "Carrier Partners", "impact": "Must provide per-parcel tracking events. Integration contracts change." },
      { "group": "Finance/Billing", "impact": "Can issue partial refunds and process per-parcel insurance claims accurately" },
      { "group": "Engineering", "impact": "Major domain model refactor, API versioning, data migration, event schema changes" }
    ]
  },

  "confidence": {
    "level": 82,
    "reasoning": "The business need is clearly stated and well-understood: parcel-level tracking for partial delivery detection. The domain of logistics tracking is well-established with standard patterns. The PM's examples (3/5 delivered, parcel lost, partial receipt dispute) confirm the core use cases. Confidence is not higher because some operational details are unspecified but inferrable from industry standards.",
    "high_confidence_areas": [
      "Parcel as independently trackable entity with own lifecycle",
      "Shipment status must be derived from parcel states, never set independently",
      "Terminal state immutability for parcels",
      "Per-parcel POD requirement",
      "Dispute must reference specific parcels",
      "Core state machine transitions for parcels"
    ],
    "low_confidence_areas": [
      "Exact failed delivery attempt policy (how many attempts before marking Held/Returned) — this is operational policy that varies by carrier and customer tier",
      "Whether the existing single-tracking-number shipments need data migration or just forward-compatibility",
      "Parcel repackaging/splitting rules — rare edge case with no stated requirements",
      "SLA monitoring thresholds per parcel vs per shipment",
      "Whether carrier assignment is per-parcel or per-shipment in the current system"
    ],
    "assumptions": [
      "The Shipment remains the aggregate root and customer-facing entity; Parcels are entities within the Shipment aggregate",
      "Each physical box/package maps 1:1 to a Parcel entity",
      "The system integrates with external carriers who provide per-parcel tracking events",
      "POD is required for delivery confirmation — not optional",
      "The refactor will maintain backward compatibility with existing shipment-level APIs during transition"
    ]
  },

  "escalations": [],

  "rejection_reasons": []
}

